    description:
      'Returns a list of bill credit card payments. Use the `cursor` parameter to paginate through the results.',
    stainlessPath: '(resource) qbd.bill_credit_card_payments > (method) list',
    qualified: 'client.qbd.billCreditCardPayments.list',
