    endpoint: '/quickbooks-desktop/inventory-assembly-items',
    httpMethod: 'post',
    summary: 'Create an inventory assembly item',
    description: 'Creates an inventory assembly item that bundles existing inventory items.',
    stainlessPath: '(resource) qbd.inventory_assembly_items > (method) create',
