      'buildNotificationThreshold?: number;',
      'classId?: string;',
      'externalId?: string;',
      'inventoryDate?: string;',
      'isActive?: boolean;',
      'lines?: { inventoryItemId?: string; quantity?: number; }[];',
      'maximumQuantityOnHand?: number;',
      'parentId?: string;',
      'preferredVendorId?: string;',
      'purchaseCost?: string;',
      'purchaseDescription?: string;',
      'purchaseTaxCodeId?: string;',
