      "lines?: { amount?: string; classId?: string; customFields?: { name: string; ownerId: string; value: string; }[]; description?: string; inventorySiteId?: string; inventorySiteLocationId?: string; itemId?: string; linkToTransactionLine?: { transactionId: string; transactionLineId: string; }; lotNumber?: string; otherCustomField1?: string; otherCustomField2?: string; overrideItemAccountId?: string; priceLevelId?: string; priceRuleConflictStrategy?: 'base_price' | 'zero'; quantity?: number; rate?: string; ratePercent?: string; salesTaxCodeId?: string; serialNumber?: string; serviceDate?: string; unitOfMeasure?: string; }[];",
