      'applyToTransactions?: { transactionId: string; applyCredits?: { appliedAmount: string; creditTransactionId: string; overrideCreditApplication?: boolean; }[]; discountAccountId?: string; discountAmount?: string; discountClassId?: string; paymentAmount?: string; }[];',
      "creditCardTransaction?: { request?: { address?: string; commercialCardCode?: string; expirationMonth?: number; expirationYear?: number; name?: string; number?: string; postalCode?: string; transactionMode?: 'card_not_present' | 'card_present'; transactionType?: 'authorization' | 'capture' | 'charge' | 'refund' | 'voice_authorization'; }; response?: { authorizationCode?: string; avsStreetStatus?: 'fail' | 'not_available' | 'pass'; avsZipStatus?: 'fail' | 'not_available' | 'pass'; cardSecurityCodeMatch?: 'fail' | 'not_available' | 'pass'; clientTransactionId?: string; creditCardTransactionId?: string; merchantAccountNumber?: string; paymentGroupingCode?: number; paymentStatus?: 'completed' | 'unknown'; reconBatchId?: string; statusCode?: number; statusMessage?: string; transactionAuthorizationStamp?: number; transactionAuthorizedAt?: string; }; };",
